array_types.code:
type OBR_Data_Field_Array is array (0 .. 1) of OBR_Data_Element with
   Component_Size => 8,
   Size           => 16;

type OBR_nBOOT_Field_Array is array (0 .. 1) of Boolean with
   Component_Size => 1,
   Size           => 2;

record_types.code:
type ACR_Register is record
   LATENCY : ACR_LATENCY_Field := 16#0#;
   Reserved_3_3 : HAL.Bit := 16#0#;
   PRFTBE : Boolean := True;
   PRFTBS : Boolean := True;
   Reserved_6_31 : HAL.UInt26 := 16#0#;
end record;

type CR_Register is record
   PG : Boolean := False;
   PER : Boolean := False;
   MER : Boolean := False;
   Reserved_3_3 : HAL.Bit := 16#0#;
   OPTPG : Boolean := False;
   OPTER : Boolean := False;
   STRT : Boolean := False;
   LOCK : Boolean := True;
   Reserved_8_8 : HAL.Bit := 16#0#;
   OPTWRE : Boolean := False;
   ERRIE : Boolean := False;
   Reserved_11_11 : HAL.Bit := 16#0#;
   EOPIE : Boolean := False;
   FORCE_OPTLOAD : Boolean := False;
   Reserved_14_31 : HAL.UInt18 := 16#0#;
end record;

type Flash_Peripheral is record
   ACR : aliased ACR_Register;
   KEYR : aliased HAL.UInt32;
   OPTKEYR : aliased HAL.UInt32;
   SR : aliased SR_Register;
   CR : aliased CR_Register;
   AR : aliased HAL.UInt32;
   OBR : aliased OBR_Register;
   WRPR : aliased HAL.UInt32;
end record;

type OBR_Data_Field (As_Array : Boolean := False) is record
   case As_Array is
      when False =>
         Val : HAL.UInt16;
      when True =>
         Arr : OBR_Data_Field_Array;
   end case;
end record;

type OBR_nBOOT_Field (As_Array : Boolean := False) is record
   case As_Array is
      when False =>
         Val : HAL.UInt2;
      when True =>
         Arr : OBR_nBOOT_Field_Array;
   end case;
end record;

type OBR_Register is record
   OPTERR : Boolean;
   RDPRT : OBR_RDPRT_Field;
   Reserved_3_7 : HAL.UInt5;
   WDG_SW : Boolean;
   nRST_STOP : Boolean;
   nRST_STDBY : Boolean;
   nBOOT : OBR_nBOOT_Field;
   VDDA_MONITOR : Boolean;
   RAM_PARITY_CHECK : Boolean;
   BOOT_SEL : Boolean;
   Data : OBR_Data_Field;
end record;

type SR_Register is record
   BSY : Boolean := False;
   Reserved_1_1 : HAL.Bit := 16#0#;
   PGERR : Boolean := False;
   Reserved_3_3 : HAL.Bit := 16#0#;
   WRPRT : Boolean := False;
   EOP : Boolean := False;
   Reserved_6_31 : HAL.UInt26 := 16#0#;
end record;

variables.code:
Flash_Periph : aliased Flash_Peripheral with
   Import,
   Address => Flash_Base;
